// Generated by OrchestKit Claude Plugin

/**
 * Unit tests for the rewritten team-size-gate (#2561).
 *
 * The old gate counted members from ~/.claude/teams/<name>/config.json, which
 * nothing writes under CC 2.1.178+ implicit teams → it silently never fired.
 * The rewrite counts spawns in a session-scoped ledger and warns (default) or
 * blocks (opt-in) on high fan-out. These tests drive the real ledger via a
 * temp HOME.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync, existsSync, readFileSync, writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import { fileURLToPath } from 'node:url';
import type { HookInput } from '../../../types.js';
import { teamSizeGate, isPremiumModel, ledgerPath } from '../../../pretool/task/team-size-gate.js';

const ENV_KEYS = ['HOME', 'ORK_TEAM_SIZE_MAX', 'ORK_TEAM_OPUS_MAX', 'ORK_TEAM_SIZE_HARD', 'ORK_NO_TEAM_SIZE_GATE'];
let saved: Record<string, string | undefined>;
let home: string;

// CC renamed Task -> Agent and hooks.json registers this dispatcher under the `Agent`
// matcher, so `Agent` is what every live invocation actually carries. The suite used to
// feed 'Task' here — which passed while the hook early-returned on every real spawn.
function spawn(model: string, session = 'sess-1', toolName = 'Agent'): HookInput {
  return { tool_name: toolName, session_id: session, tool_input: { model, description: `spawn ${model}` } } as unknown as HookInput;
}

beforeEach(() => {
  saved = Object.fromEntries(ENV_KEYS.map(k => [k, process.env[k]]));
  home = mkdtempSync(join(tmpdir(), 'ork-team-'));
  process.env.HOME = home;
  for (const k of ENV_KEYS.slice(1)) delete process.env[k];
});
afterEach(() => {
  for (const [k, v] of Object.entries(saved)) { if (v === undefined) delete process.env[k]; else process.env[k] = v; }
  rmSync(home, { recursive: true, force: true });
});

describe('isPremiumModel', () => {
  it('detects opus + fable by shortName and full ID', () => {
    for (const m of ['opus', 'fable', 'claude-opus-4-8', 'claude-fable-5']) expect(isPremiumModel(m)).toBe(true);
  });
  it('rejects sonnet/haiku/inherit/empty', () => {
    for (const m of ['sonnet', 'haiku', 'claude-haiku-4-5-20251001', 'inherit', '']) expect(isPremiumModel(m)).toBe(false);
  });
});

describe('team-size-gate — dispatch (regression: the gate must actually FIRE)', () => {
  // This hook shipped DEAD: it guarded `tool_name !== 'Task'` while hooks.json registers
  // the dispatcher under the `Agent` matcher, so it early-returned on every real spawn.
  // The old suite passed anyway because it fed 'Task'. These tests read the REAL matcher
  // out of hooks.json, so a future tool rename fails here instead of silently killing the hook.
  const hooksJsonPath = fileURLToPath(new URL('../../../../hooks.json', import.meta.url));
  const hooksJson = JSON.parse(readFileSync(hooksJsonPath, 'utf8')) as {
    hooks: Record<string, Array<{ matcher?: string }>>;
  };

  const preToolMatchers = (hooksJson.hooks.PreToolUse ?? [])
    .map(e => e.matcher ?? '')
    .filter(m => /Agent|Task/.test(m));

  it('hooks.json registers a spawn matcher we recognise', () => {
    expect(preToolMatchers.length).toBeGreaterThan(0);
  });

  it.each(preToolMatchers.flatMap(m => m.split('|')).filter(t => /Agent|Task/.test(t)))(
    'fires for tool_name=%s (the name CC actually sends)',
    toolName => {
      const r = teamSizeGate(spawn('opus', `sess-${toolName}`, toolName));
      // A live spawn must be COUNTED, not silently skipped.
      const led = JSON.parse(readFileSync(ledgerPath(`sess-${toolName}`), 'utf8'));
      expect(led.total).toBe(1);
      expect(r.continue).toBe(true);
    },
  );
});

describe('team-size-gate — passthrough', () => {
  it('ignores non-spawn tools', () => {
    const r = teamSizeGate({ tool_name: 'Bash', session_id: 's', tool_input: {} } as unknown as HookInput);
    expect(r.suppressOutput).toBe(true);
    expect(r.continue).toBe(true);
  });
  it('ignores spawns with no session_id (cannot key)', () => {
    const r = teamSizeGate({ tool_name: 'Task', session_id: '', tool_input: { model: 'opus' } } as unknown as HookInput);
    expect(r.suppressOutput).toBe(true);
  });
  it('opt-out via ORK_NO_TEAM_SIZE_GATE=1', () => {
    process.env.ORK_NO_TEAM_SIZE_GATE = '1';
    const r = teamSizeGate(spawn('opus'));
    expect(r.suppressOutput).toBe(true);
  });
});

describe('ledger counting', () => {
  it('increments total per spawn and counts premium separately', () => {
    teamSizeGate(spawn('sonnet'));
    teamSizeGate(spawn('opus'));
    teamSizeGate(spawn('claude-fable-5'));
    const led = JSON.parse(readFileSync(ledgerPath('sess-1'), 'utf8'));
    expect(led.total).toBe(3);
    expect(led.opus).toBe(2); // opus + fable, not sonnet
    expect(led.schema).toBe('team-spawns/1.0');
  });
  it('keys ledgers per session', () => {
    teamSizeGate(spawn('opus', 'A'));
    teamSizeGate(spawn('opus', 'B'));
    expect(JSON.parse(readFileSync(ledgerPath('A'), 'utf8')).total).toBe(1);
    expect(JSON.parse(readFileSync(ledgerPath('B'), 'utf8')).total).toBe(1);
  });
});

describe('advisory posture (default — never blocks)', () => {
  it('warns exactly once when total crosses the threshold', () => {
    process.env.ORK_TEAM_SIZE_MAX = '3';
    expect(teamSizeGate(spawn('sonnet')).systemMessage).toBeUndefined();
    expect(teamSizeGate(spawn('sonnet')).systemMessage).toBeUndefined();
    const crossing = teamSizeGate(spawn('sonnet')); // 3rd = threshold
    expect(crossing.continue).toBe(true); // never denies
    expect(crossing.systemMessage).toContain('High subagent fan-out');
    expect(teamSizeGate(spawn('sonnet')).systemMessage).toBeUndefined(); // 4th: silent again
  });
  it('warns on premium threshold', () => {
    process.env.ORK_TEAM_OPUS_MAX = '2';
    teamSizeGate(spawn('opus'));
    const r = teamSizeGate(spawn('opus')); // 2nd premium
    expect(r.continue).toBe(true);
    expect(r.systemMessage).toContain('premium-model fan-out');
  });
});

describe('hard posture (ORK_TEAM_SIZE_HARD=1)', () => {
  it('denies the spawn that would exceed the total cap', () => {
    process.env.ORK_TEAM_SIZE_HARD = '1';
    process.env.ORK_TEAM_SIZE_MAX = '2';
    expect(teamSizeGate(spawn('sonnet')).continue).toBe(true);
    expect(teamSizeGate(spawn('sonnet')).continue).toBe(true); // total now 2
    const denied = teamSizeGate(spawn('sonnet')); // would be 3rd
    expect(denied.continue).toBe(false);
    expect(denied.stopReason).toContain('Fan-out Limit');
  });
  it('denies premium spawn over the opus cap but allows non-premium', () => {
    process.env.ORK_TEAM_SIZE_HARD = '1';
    process.env.ORK_TEAM_OPUS_MAX = '1';
    expect(teamSizeGate(spawn('opus')).continue).toBe(true); // opus=1
    expect(teamSizeGate(spawn('opus')).continue).toBe(false); // opus over cap → deny
    expect(teamSizeGate(spawn('sonnet')).continue).toBe(true); // non-premium still fine
  });
});

describe('resilience', () => {
  it('survives a corrupt ledger by starting fresh', () => {
    const p = ledgerPath('sess-1');
    teamSizeGate(spawn('opus')); // create it
    writeFileSync(p, '{ not json');
    const r = teamSizeGate(spawn('opus'));
    expect(r.continue).toBe(true);
    expect(existsSync(p)).toBe(true);
    expect(JSON.parse(readFileSync(p, 'utf8')).total).toBe(1); // reset, then this spawn
  });
});
